	@Test
	void matchesDefaultJoinOrderForBindingSetAssignmentPriority() throws Exception {
		PriorityStatistics statistics = new PriorityStatistics();
		Set<String> labels = Set.of(VALUES_SHARED, P_OTHER, P_USES);

		List<String> defaultOrder = optimizeWithDefault(BINDING_SET_ASSIGNMENT_QUERY, statistics, labels);
		List<String> learnedOrder = optimizeWithLearned(BINDING_SET_ASSIGNMENT_QUERY, statistics, labels);

		assertEquals(defaultOrder, learnedOrder,
				"Learned optimizer should keep BindingSetAssignment priority parity with QueryJoinOptimizer");
	}

