	@Test
	void matchesDefaultPairPriorityForBindingSetAssignment() {
		PriorityStatistics statistics = new PriorityStatistics();
		BindingSetAssignment values = bindingSetAssignment("shared",
				SimpleValueFactory.getInstance().createLiteral("shared-1"),
				SimpleValueFactory.getInstance().createLiteral("shared-2"));
		StatementPattern other = new StatementPattern(Var.of("otherS"),
				Var.of("otherP", SimpleValueFactory.getInstance().createIRI(P_OTHER)),
				Var.of("otherO"));
		StatementPattern usesValues = new StatementPattern(Var.of("usesS"),
				Var.of("usesP", SimpleValueFactory.getInstance().createIRI(P_USES)),
				Var.of("shared"));
		QueryRoot baselineRoot = new QueryRoot(new Join(values, new Join(other, usesValues)));
		QueryRoot learnedRoot = baselineRoot.clone();

		QueryJoinOptimizer defaultOptimizer = new QueryJoinOptimizer(statistics, new EmptyTripleSource());
		defaultOptimizer.optimize(baselineRoot, null, null);
		LearnedQueryJoinOptimizer learnedOptimizer = new LearnedQueryJoinOptimizer(statistics, new EmptyTripleSource(),
				new EmptyJoinStatsProvider());
		learnedOptimizer.optimize(learnedRoot, null, null);

		List<String> defaultOrder = collectOrderedLabels(baselineRoot, Set.of(VALUES_SHARED, P_OTHER, P_USES));
		List<String> learnedOrder = collectOrderedLabels(learnedRoot, Set.of(VALUES_SHARED, P_OTHER, P_USES));
		assertEquals(defaultOrder, learnedOrder,
				"Learned optimizer should preserve BindingSetAssignment pair-priority behavior");
		assertEquals(P_OTHER, learnedOrder.get(0));
		assertEquals(Set.of(VALUES_SHARED, P_USES), Set.copyOf(learnedOrder.subList(1, 3)));
	}

