	private List<String> collectOrderedLabels(TupleExpr tupleExpr, Set<String> targetLabels) {
		List<TupleExpr> leaves = new ArrayList<>();
		collectLeaves(tupleExpr, leaves);
		List<String> labels = new ArrayList<>(leaves.size());
		for (TupleExpr leaf : leaves) {
			String label = tupleExprLabel(leaf);
			if (label != null && targetLabels.contains(label)) {
				labels.add(label);
			}
		}
		return labels;
	}

	private List<String> orderLabels(List<TupleExpr> expressions, Set<String> targetLabels) {
		List<String> labels = new ArrayList<>(expressions.size());
		for (TupleExpr expression : expressions) {
			String label = tupleExprLabel(expression);
			if (label != null && targetLabels.contains(label)) {
				labels.add(label);
			}
		}
		return labels;
	}

	private void collectLeaves(TupleExpr tupleExpr, List<TupleExpr> target) {
		if (tupleExpr instanceof QueryRoot) {
			collectLeaves(((QueryRoot) tupleExpr).getArg(), target);
			return;
		}
		if (tupleExpr instanceof Join) {
			Join join = (Join) tupleExpr;
			collectLeaves(join.getLeftArg(), target);
			collectLeaves(join.getRightArg(), target);
			return;
		}
		if (tupleExpr instanceof UnaryTupleOperator) {
			collectLeaves(((UnaryTupleOperator) tupleExpr).getArg(), target);
			return;
		}
		if (tupleExpr instanceof BinaryTupleOperator) {
			BinaryTupleOperator binary = (BinaryTupleOperator) tupleExpr;
			collectLeaves(binary.getLeftArg(), target);
			collectLeaves(binary.getRightArg(), target);
			return;
		}
		target.add(tupleExpr);
	}

	private String tupleExprLabel(TupleExpr expr) {
		if (expr instanceof BindingSetAssignment) {
			BindingSetAssignment assignment = (BindingSetAssignment) expr;
			String bindingName = assignment.getBindingNames().stream().findFirst().orElse("unknown");
			return "values:" + bindingName;
		}

		StatementPattern statementPattern = extractStatementPattern(expr);
		if (statementPattern != null) {
			Var predicateVar = statementPattern.getPredicateVar();
			if (predicateVar != null && predicateVar.hasValue() && predicateVar.getValue() instanceof IRI) {
				return predicateVar.getValue().stringValue();
			}
		}

		if (expr instanceof Filter) {
			Filter filter = (Filter) expr;
			if (filter.getCondition() instanceof Compare) {
				Compare compare = (Compare) filter.getCondition();
				Value value = constantValue(compare.getRightArg());
				if (!(value instanceof IRI)) {
					value = constantValue(compare.getLeftArg());
				}
				if (value instanceof IRI) {
					return value.stringValue();
				}
			}
		}

		return null;
	}

	private StatementPattern extractStatementPattern(TupleExpr expr) {
		if (expr instanceof StatementPattern) {
			return (StatementPattern) expr;
		}
		if (expr instanceof Filter) {
			TupleExpr arg = ((Filter) expr).getArg();
			while (arg instanceof Filter) {
				arg = ((Filter) arg).getArg();
			}
			if (arg instanceof StatementPattern) {
				return (StatementPattern) arg;
			}
		}
		return null;
	}

	private Value constantValue(org.eclipse.rdf4j.query.algebra.ValueExpr expr) {
		if (expr instanceof ValueConstant) {
			return ((ValueConstant) expr).getValue();
		}
		if (expr instanceof Var) {
			Var var = (Var) expr;
			if (var.hasValue()) {
				return var.getValue();
			}
		}
		return null;
	}

	private BindingSetAssignment bindingSetAssignment(String bindingName, Value... values) {
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingNames(Set.of(bindingName));

		List<org.eclipse.rdf4j.query.BindingSet> bindingSets = new ArrayList<>(values.length);
		for (Value value : values) {
			MapBindingSet bindingSet = new MapBindingSet();
			bindingSet.addBinding(bindingName, value);
			bindingSets.add(bindingSet);
		}
		assignment.setBindingSets(bindingSets);
		return assignment;
	}

